-- 네이버 상품정보제공고시 — 상품군별 입력 스키마 카탈로그
--
-- 실행: mysql -h ydata.co.kr -u ydatasvc -p'...' yd_mall < scripts/migrate_naver_notice_schema.sql
-- 설계: docs/사이트개선/네이버_스마트스토어_연동.md §6.4
--
-- 왜 필요한가:
--   고시정보는 상품군마다 필수 필드가 전혀 다르다(36종). 예전에는 관리자가
--   `notice_defaults_json` textarea 에 JSON 을 직접 손으로 적어야 했는데, 이는
--   운영자가 할 수 있는 입력이 아니다. 상품군별 필드 목록을 여기에 카탈로그로
--   두고 화면이 그걸 순회해 **일반 입력폼을 생성**한다. JSON 은 서버가 조립한다.
--
--   시드 데이터는 2026-07-21 `GET /v1/products-for-provided-notice` **실응답**에서
--   생성했다(36종 전체). 자격증명이 없는 새 몰에서도 폼이 바로 동작해야 하므로
--   카탈로그는 제품의 일부로 배포에 싣는다. 최신화가 필요하면 관리자 화면의
--   [네이버에서 상품군 수집] 버튼이 같은 API 로 덮어쓴다(source='NAVER').
--
-- ⚠ 네이버 응답에는 **필수 여부가 없다.** 그래서 모든 필드의 required 는 false 다.
--   실제 필수 항목은 등록 400 응답으로만 알 수 있다. 지어내지 말 것.
--
-- 멱등: CREATE TABLE IF NOT EXISTS + INSERT ... ON DUPLICATE KEY UPDATE.

CREATE TABLE IF NOT EXISTS naver_notice_schema (
    notice_type   VARCHAR(64)  NOT NULL COMMENT '네이버 상품군 코드(UPPER_SNAKE) — 예: DIET_FOOD',
    key_name      VARCHAR(64)  NOT NULL COMMENT '페이로드 하위 객체 키(camelCase) — 예: dietFood',
    label         VARCHAR(100) NOT NULL COMMENT '화면 표기명',
    fields_json   JSON         NOT NULL COMMENT '[{name,label,type,required,maxLength,hint}] — 공통 5필드 제외',
    source        VARCHAR(16)  NOT NULL DEFAULT 'SEED' COMMENT 'SEED | NAVER',
    display_order INT          NOT NULL DEFAULT 100,
    fetched_at    TIMESTAMP    NULL DEFAULT NULL,
    updated_at    TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (notice_type)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='네이버 상품정보제공고시 상품군별 입력 스키마';

